// Tenant slug sent by the dashboard
const tenantSlug = $('Webhook').first().json.body?.tenant_slug || '';

const rows = $input.all().map(i => i.json);

const filtered = rows.filter(row => {
  if (!tenantSlug) return true;
  const slug = (row['tenant_slug'] || row['Tenant Slug'] || row['tenant'] || '').toLowerCase();
  return !slug || slug === tenantSlug.toLowerCase();
});

// Return most recent 100 turns for the training log
const result = filtered.slice(-100).reverse().map(row => ({
  session_id:    row['session_id']    || row['Session ID']    || row['call_id']       || '',
  phone_number:  row['phone_number']  || row['Phone']         || row['caller']        || '—',
  channel:       (row['channel']      || row['Channel']       || row['type']          || 'call').toLowerCase(),
  user_message:  row['user_message']  || row['User Message']  || row['customer_input']|| row['transcript'] || row['question'] || '',
  ai_response:   row['ai_response']   || row['AI Response']   || row['response']      || row['reply']      || row['answer']   || '',
  intent:        row['intent']        || row['Intent']        || row['detected_intent']|| '',
  model:         row['model']         || row['Model']         || 'Claude',
  timestamp:     row['timestamp']     || row['Timestamp']     || row['created_at']    || row['Date']       || '',
  tenant_slug:   row['tenant_slug']   || row['Tenant Slug']   || tenantSlug
}));

return [{ json: { result } }];
